# requirements.R

# Nutze das benutzerdefinierte Library-Verzeichnis, falls gesetzt
if (!is.na(Sys.getenv("R_LIBS_USER", unset = NA))) {
  .libPaths(Sys.getenv("R_LIBS_USER"))
}

install_if_missing &lt;- function(pkg) {
  if (!pkg %in% rownames(installed.packages())) {
    install.packages(pkg, repos = "https://cloud.r-project.org")
  }
}

# Liste der benötigten Pakete – hier kannst du jederzeit erweitern
pkgs &lt;- c(
  "tidyverse",
  "knitr",
  "rmarkdown"
)

sapply(pkgs, install_if_missing)

dplyr: filter()

filter() wählt Zeilen/Beobachtungen (rows) basierend auf Bedingungen


penguins |&gt;
  filter(species == "Gentoo") |&gt;
  head(n = 4)

# A tibble: 4 × 8
  species island bill_length_mm bill_depth_mm flipper_length_mm body_mass_g
  &lt;fct&gt;   &lt;fct&gt;           &lt;dbl&gt;         &lt;dbl&gt;             &lt;int&gt;       &lt;int&gt;
1 Gentoo  Biscoe           46.1          13.2               211        4500
2 Gentoo  Biscoe           50            16.3               230        5700
3 Gentoo  Biscoe           48.7          14.1               210        4450
4 Gentoo  Biscoe           50            15.2               218        5700
# ℹ 2 more variables: sex &lt;fct&gt;, year &lt;int&gt;


